class table_format:

    header: list[str] = []

    def __init__(self, pdf_path: Path) -> None:
        if re.match(r"[^\d]+", pdf_path.stem) or len(pdf_path.stem) not in [6, 8]: 
            raise ValueError(f"Invalid file name: {pdf_path.stem}")
        self.file_date = int(pdf_path.stem[0:6])
        self.origin_file_date = int(pdf_path.stem)
        self.pdf_path = pdf_path
    
    @classmethod
    def return_lines_have_cols(cls, lines) -> tuple[list[list[dict]], bool]:
        return (lines, True)

    @property
    def fmt_type(self):
        if self.origin_file_date < 999999: # 8桁の日付でない場合、fmt_4とみなす
            return fmt_4(self.pdf_path)
        elif 200101 <= self.file_date <= 200308:
            return fmt_1(self.pdf_path)
        elif 200309 <= self.file_date <= 201211:
            return fmt_2(self.pdf_path)
        elif 201212 <= self.file_date <= 201912:
            return fmt_3(self.pdf_path)
        elif 202001 <= self.file_date:
            return fmt_5(self.pdf_path)
        raise ValueError(f"Unsupported file date: {self.file_date}")

    @property
    def getDate(self) -> int:
        return self.file_date


class fmt_1(table_format):

    header = [
        "約定日",
        "銘柄コード",
        "銘柄略称",
        "前場始値",
        "前場高値",
        "前場安値",
        "前場終値",
        "後場始値",
        "後場高値",
        "後場安値",
        "後場終値",
        "気配区分",
        "最終特別気配",
        "売買高",
        "売買単位",
    ]
    
    def __init__(self, pdf_path:Path) -> None:
        self.file_date = pdf_path
    
    @classmethod
    def return_lines_have_cols(cls, lines) -> tuple[list[list[dict]], bool]:
        col_line_1 = sorted(lines[0], key=lambda x: x['x0'])
        col_line_2 = sorted(lines[1], key=lambda x: x['x0'])

        if col_line_1[0]['text'] == '気':
            return (lines[1:], True)  # 1行目は不要なので除外
        if col_line_1[0]['text'] == '最' and col_line_2[0]['text'] == '気':
            return (lines[2:], True)  # 1行目と2行目は不要なので除外
        elif col_line_1[0]['text'] == '約':
            return (lines, True)  # 1行目も必要なのでそのまま返す
        else:
            return (lines, False)  # 1行目がどちらでもない場合、フラグをTrueにして返す
    
    @classmethod
    def make_rows_single_line(cls, all_rows: list[list[str]], page_number: int = 0) -> None:
        # Dummy method
        pass

    @property
    def name(self):
        return "fmt_1"
    
    @property
    def sleep_time(self) -> float:
        return 0.1
    

class fmt_2(table_format):

    header = [
        "約定日",
        "銘柄",
        "銘柄略称",
        "前場始値",
        "前場高値",
        "前場安値",
        "前場終値",
        "後場始値",
        "後場高値",
        "後場安値",
        "後場終値",
        "最終特別気配",
        "売買高（株/口）",
        "うち立会外売買高（株/口）",
        "売買単位",
    ]

    def __init__(self, pdf_path: Path) -> None:
        super().__init__(pdf_path)
    
    @classmethod
    def return_lines_have_cols(cls, lines: list[list[dict]]) -> tuple[list[list[dict]], bool]:
        col_line_2 = sorted(lines[1], key=lambda x: x['x0'])
        col_line_3 = sorted(lines[2], key=lambda x: x['x0'])
        col_line_end = sorted(lines[-1], key=lambda x: x['x0'])

        # 2行目が「気配(株/口)売買高」、3行目が「(株/口)」、4行目が「(株)東京証券取引所」の場合、2～4行目は不要なので除外
        if col_line_2[0]['text'] == '気' and col_line_3[0]['text'] == '(' and col_line_end[0]['text'] == '(':
            lines.remove(lines[-1])
            lines.remove(lines[2])
            lines.remove(lines[1]) # 2行目と3行目は不要なので除外
            return (lines, True)
        else:
            return (lines, False)  # 1行目がどちらでもない場合、フラグをTrueにして返す

    @classmethod
    def make_rows_single_line(cls, all_rows: list[list[str]]):
        # Dummy method
        pass
    
    @property
    def name(self):
        return "fmt_2"
    
    @property
    def sleep_time(self) -> float:
        return 0.5


class fmt_3(table_format):

    header = [
        "約定日",
        "銘柄",
        "銘柄略称",
        "前場始値",
        "前場高値",
        "前場安値",
        "前場終値",
        "後場始値",
        "後場高値",
        "後場安値",
        "後場終値",
        "最終特別気配",
        "売買高（株/口）",
        "うち立会外売買高（株/口）",
        "売買単位",
    ]

    def __init__(self, pdf_path: Path) -> None:
        super().__init__(pdf_path)

    @classmethod
    def return_lines_have_cols(cls, lines: list[list[dict]]) -> tuple[list[list[dict]], bool]:
        col_line_2 = sorted(lines[1], key=lambda x: x['x0'])
        col_line_3 = sorted(lines[2], key=lambda x: x['x0'])
        col_line_end = sorted(lines[-1], key=lambda x: x['x0'])

        # 2行目が「気配(株/口)売買高」、3行目が「(株/口)」、4行目が「(株)東京証券取引所」の場合、2～4行目は不要なので除外
        if col_line_2[0]['text'] == '気' and col_line_3[0]['text'] in ['(', '（'] and col_line_end[0]['text'] in ['(', '（']:
            lines.remove(lines[-1])
            lines.remove(lines[2])
            lines.remove(lines[1]) # 2行目と3行目は不要なので除外
            return (lines, True)
        else:
            return (lines, False)  # 1行目がどちらでもない場合、フラグをTrueにして返す
        
    @classmethod
    def make_rows_single_line(cls, all_rows: list[list[str]]) -> None:
        origin_length = len(all_rows)
        for i, rows in enumerate(all_rows[::-1], start=1):
            reverse_i = origin_length - (i + 1)# 逆順のインデックスを通常のインデックスに変換
            remain_rows_ele = [r for r in rows if r != '']
            if len(remain_rows_ele) == 1 and reverse_i > 0:
                exist_target_index = rows.index(remain_rows_ele[0])

                # row[2]は、「銘柄略称」の項目であり、これを直前の行の「銘柄略称」の項目に結合する
                all_rows[reverse_i][2] = all_rows[reverse_i][2] + all_rows[reverse_i+1][exist_target_index]
                del all_rows[reverse_i+1]

    @property
    def name(self):
        return "fmt_3"

    @property
    def sleep_time(self) -> float:
        return 0.5


class fmt_4(table_format):

    header = [
        "年月日",
        "コード",
        "銘柄名",
        "前場始値",
        "前場高値",
        "前場安値",
        "前場終値",
        "後場始値",
        "後場高値",
        "後場安値",
        "後場終値",
    ]

    def __init__(self, pdf_path: Path) -> None:
        super().__init__(pdf_path)

    @classmethod
    def return_lines_have_cols(cls, lines, page_number: int = 0) -> tuple[list[list[dict]], bool]:
        return (lines, True)
    
    @classmethod
    def make_rows_single_line(cls, all_rows: list[list[str]]):
        # Dummy method
        pass

    @classmethod
    def split_pdf_by_date_iter(cls, pdf_path: Path) -> None:
        tmp:dict[str, list[dict[str, int]]] = {}
        with pp.open(pdf_path) as pdf:
            # tmp = {"20200106" : [{"page_start":   0, "page_end": 100}, 
            #                      {"page_start": 160, "page_end": 200}, 
            #                      ...
            #                     ],
            #        "20200107" : [{"page_start": 101, "page_end": 159},
            #                      ...
            for page in pdf.pages:
                lines = page.extract_text_simple().split("\n")
                date_list = []
                for line in lines:
                    date = re.match(r"\d{8}", line)
                    if date:
                        if date.group() not in date_list:
                            date_list.append(date.group())
                for date in date_list:
                    if date not in tmp:
                        page_start, page_end = page.page_number, page.page_number
                        tmp[date] = [{"page_start": page_start, "page_end": page_end}]
                    else:
                        page_end = page.page_number
                        if tmp[date][-1]["page_end"] == page_end - 1:
                            tmp[date][-1]["page_end"] = page_end
                        else:
                            tmp[date].append({"page_start": page_end, "page_end": page_end})
                
                page.flush_cache()
                
                print(f"Processed page {page.page_number}/{len(pdf.pages)}")
        
        for date, ranges in tmp.items():
            file_name, page_ranges = f"{date}.pdf", ",".join([f"{r['page_start']}-{r['page_end']}" if r['page_start'] != r['page_end'] else f"{r['page_start']}" for r in ranges])
            output_path = pdf_path.parent / f"tmp_{cls.__name__}" / file_name
            command = [
                constant.path_to_cpdf, # cpdfの実行ファイル名であり、別途インストールが必要
                str(pdf_path),
                page_ranges,
                "-o",
                str(output_path),
            ]
            print(f"Executing command: {command}")
            subprocess.call(command, timeout=60) # 60秒以内に処理が終わらなければタイムアウトさせる
        
        del tmp

        return


    @property
    def name(self):
        return "fmt_4"
    
    @property
    def sleep_time(self) -> float:
        return 1.0
    
